import React, { useState, useEffect, useRef } from 'react';
import { startChat, nextUser, endChat, getQueueSize } from '../services/api';
import useChat from '../websocket/useChat';
import MessageBubble from '../components/MessageBubble';
import styles from './ChatPage.module.css';

/**
 * Main chat page.
 * Handles matchmaking state and renders the chat window.
 */
export default function ChatPage({ userId }) {
  const [status, setStatus] = useState('IDLE'); // IDLE | WAITING | MATCHED | ENDED
  const [roomId, setRoomId] = useState(null);
  const [inputText, setInputText] = useState('');
  const [queueSize, setQueueSize] = useState(0);
  const [actionLoading, setActionLoading] = useState(false);
  const messagesEndRef = useRef(null);
  const typingDebounceRef = useRef(null);

  const { messages, connected, partnerTyping, sendMessage, sendTyping } = useChat(roomId, userId);

  // Auto-scroll to latest message
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, partnerTyping]);

  // Poll queue size every 5s while waiting
  useEffect(() => {
    if (status !== 'WAITING') return;
    const interval = setInterval(async () => {
      try {
        const res = await getQueueSize();
        setQueueSize(res.data ?? 0);
      } catch (_) {}
    }, 5000);
    return () => clearInterval(interval);
  }, [status]);

  const handleStart = async () => {
    setActionLoading(true);
    try {
      const res = await startChat(userId);
      if (res.data.status === 'MATCHED') {
        setRoomId(res.data.roomId);
        setStatus('MATCHED');
      } else {
        setStatus('WAITING');
      }
    } catch (err) {
      console.error(err);
    } finally {
      setActionLoading(false);
    }
  };

  const handleNext = async () => {
    setActionLoading(true);
    setRoomId(null);
    try {
      const res = await nextUser(userId);
      if (res.data.status === 'MATCHED') {
        setRoomId(res.data.roomId);
        setStatus('MATCHED');
      } else {
        setStatus('WAITING');
      }
    } catch (err) {
      console.error(err);
    } finally {
      setActionLoading(false);
    }
  };

  const handleEnd = async () => {
    setActionLoading(true);
    try {
      await endChat(userId);
      setRoomId(null);
      setStatus('ENDED');
    } catch (err) {
      console.error(err);
    } finally {
      setActionLoading(false);
    }
  };

  const handleSend = (e) => {
    e.preventDefault();
    const text = inputText.trim();
    if (!text || !connected) return;
    sendMessage(text);
    setInputText('');
  };

  const handleInputChange = (e) => {
    setInputText(e.target.value);
    // Debounce typing indicator
    clearTimeout(typingDebounceRef.current);
    typingDebounceRef.current = setTimeout(sendTyping, 300);
  };

  return (
    <div className={styles.page}>
      {/* Header */}
      <header className={styles.header}>
        <span className={styles.logo}>AnonChat</span>
        <div className={styles.headerRight}>
          {status === 'MATCHED' && (
            <span className={`${styles.dot} ${connected ? styles.online : styles.offline}`} />
          )}
          <span className={styles.statusLabel}>{statusLabel(status, connected)}</span>
        </div>
      </header>

      {/* Main area */}
      <main className={styles.main}>
        {status === 'IDLE' || status === 'ENDED' ? (
          <div className={styles.landing}>
            <p className={styles.landingText}>
              {status === 'ENDED' ? 'Chat ended.' : 'Ready to meet someone new?'}
            </p>
            <button className={styles.btnPrimary} onClick={handleStart} disabled={actionLoading}>
              {actionLoading ? 'Connecting...' : '🎲 Start Chat'}
            </button>
          </div>
        ) : status === 'WAITING' ? (
          <div className={styles.landing}>
            <div className={styles.spinner} />
            <p className={styles.landingText}>Looking for someone to chat with...</p>
            {queueSize > 0 && <p className={styles.queueInfo}>{queueSize} user(s) in queue</p>}
            <button className={styles.btnDanger} onClick={handleEnd} disabled={actionLoading}>
              Cancel
            </button>
          </div>
        ) : (
          /* Chat window */
          <div className={styles.chatWindow}>
            <div className={styles.messages}>
              {messages.map((msg, i) => (
                <MessageBubble key={i} msg={msg} isMine={msg.senderId === userId} />
              ))}
              {partnerTyping && (
                <div className={styles.typing}>Stranger is typing...</div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <form className={styles.inputRow} onSubmit={handleSend}>
              <input
                value={inputText}
                onChange={handleInputChange}
                placeholder="Type a message..."
                maxLength={1000}
                autoFocus
              />
              <button type="submit" className={styles.btnSend} disabled={!inputText.trim() || !connected}>
                Send
              </button>
            </form>
          </div>
        )}
      </main>

      {/* Footer actions when in chat */}
      {status === 'MATCHED' && (
        <footer className={styles.footer}>
          <button className={styles.btnSecondary} onClick={handleNext} disabled={actionLoading}>
            ⏭ Next User
          </button>
          <button className={styles.btnDanger} onClick={handleEnd} disabled={actionLoading}>
            ✕ End Chat
          </button>
        </footer>
      )}
    </div>
  );
}

function statusLabel(status, connected) {
  if (status === 'MATCHED') return connected ? 'Connected' : 'Reconnecting...';
  if (status === 'WAITING') return 'Searching...';
  if (status === 'ENDED') return 'Disconnected';
  return 'Anonymous Chat';
}
